var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"부상은 어떤가요, 리코리스?","JPN":"怪我はどうですか、リコリス？","ENG":"How’s the wound, Lycoris?","TWN":"傷勢怎麼樣，莉克麗絲？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"보면 알잖아. 아야야야…….","JPN":"みりゃわかるでしょ。いててて……","ENG":"You’re looking at it already. Awwww...","TWN":"看也知道吧？哎唷唷唷…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"시간을 끌다가 물러나면 된다고 그렇게 말했는데, 왜 제 지시를 안 들었죠?","JPN":"時間稼ぎだけできたら撤退していいと言ったのに、なぜ私の指示に従わなかったのですか？","ENG":"I told to not to overstay. Why didn’t you listen?","TWN":"我不是說稍微拖延一下時間就撤嗎？為什麼不聽？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"빨래를 돕는 동안 모네한테서 바보가 옮기라도 했나요?","JPN":"洗濯を手伝っている間、モネからおバカウイルスでももらったんですか？","ENG":"Did you pick up Mone’s foolishness when you were doing laundry together?","TWN":"你是莫妮不在的時候幫忙洗衣服，就變得更莫妮一樣傻嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 착각하지 마. 그냥 그 물갈퀴 달고 다니는 애가 마음에 안 들었을 뿐이니까.","JPN":"ふん、勘違いしないで。あの水かきをつけてる子が気に入らなかっただけだから。","ENG":"Hmpf, it’s not that. I just didn’t like the girl with grappling hooks.","TWN":"哼，不要誤會。我只是不喜歡那個帶著魚叉的女生而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇다고 하기엔 온 산에 다 들리게 외치던데요.","JPN":"そういうわりにはこの一帯に響くらい叫んでましたよ。","ENG":"Yet I could hear you shouting out all over the mountain.","TWN":"但是你剛叫得整座山都有聽到。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>그래도 한식구인 애가 휴가 날에 울상 짓는 꼴은 보기 싫다고!</color> 라고.","JPN":"<color=#ffd34c>でも、家族同然の子がせっかく帰省したのに、泣きそうな顔をするのは見たくないの！</color>　って。","ENG":"<color=#ffd34c>But still, I don’t want to see my colleague getting all teary while she’s on vacation!</color>","TWN":"<color=#ffd34c>但我不樂意見到人家的孩子在休假時哭喪著臉！！</color>。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"하, 한창 싸우고 있을 때 그걸 네가 어떻게 들었어?!","JPN":"た、戦いの真っ最中だったのになんであんたが聞いてるわけ！？","ENG":"H-how did you hear that? You must have been busy fighting yourself!","TWN":"你…你不是忙著對付作戰嗎？怎麼聽到的？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"메이드는 항상 귀를 열어 놓고 있어야 합니다. 주인님의 부름은 언제 들릴지 모르거든요.","JPN":"メイドは常に耳を開けておかなければなりません。ご主人様にいつ呼ばれるかわかりませんので。","ENG":"A maid must be aware of everything around her. You never know when the Master will call on you.","TWN":"女僕就是要時時刻刻打開耳朵，才能隨時聽到主人的吩咐。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"하지만 리코리스는 역시 주방보다는 육아 담당이 적합해요. 메이드장님께 건의드리겠습니다.","JPN":"しかし、リコリスはやはりキッチンより育児担当に向いています。メイド長に提案します。","ENG":"I think you are better at baby-sitting rather than kitchen work. I’ll propose a change of assignment to the Chief Maid.","TWN":"不過我看你好像不太適合廚房的工作，保母比較適合你，我會再向女僕長提出建議。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야! 너 그러면 진짜 가만 안 둬!","JPN":"ねえ！　絶対にやめてよ！","ENG":"Hey! I will never let you do that!","TWN":"喂！你敢的話我可不會放過你！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_Q","text":{"KOREA":"그 건의는 보류해야겠어요, 릴리.","JPN":"その提案は保留にしますね、リリー。","ENG":"I’ll have to put your proposal on hold, Lily.","TWN":"莉莉，你的建議我先暫時保留。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_Q","text":{"KOREA":"주인님을 섬기는 방식은 리코리스 스스로 택해야 하니까요.","JPN":"ご主人様に仕える仕事は、リコリスがみずから選ぶ必要がありますから。","ENG":"Lycoris has the right to choose how she serves the master.","TWN":"因爲服侍主人的方式，應該由莉克麗絲自己選擇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하하핫! 그 얼빠진 표정은 뭐야?","JPN":"キャハハハ！　なんだ、そのマヌケな顔！","ENG":"Kya hah hah! What’s with that look on your face?","TWN":"哈哈哈哈！看你們一副恍神的樣子！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"설마 그 둘이서 어떻게 할 수 있다고 생각한 건 아니겠지?","JPN":"まさか二人だけでどうにかなると思ったの？","ENG":"You didn’t think they could handle me, did you?","TWN":"你們該不會以為他們兩個會有什麼對策嗎？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"나, 나쁜 언니가 나타났슴다!","JPN":"わ、悪いお姉さんが現れたっす！","ENG":"The mean lady is here!","TWN":"是…壞姊姊！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오! 애꾸눈은 아니지만 역시 훌륭한 악당 해적 웃음소리야!","JPN":"おお！　眼帯はないけど、やっぱり立派な悪党海賊の笑い声だ！","ENG":"Oh! Your laughter is very pirate-ish, even though you don’t have an eye patch!","TWN":"哇喔！雖然不是獨眼龍，但是笑聲確實很像反派海盜！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"드라코, 산을 넘느라 손실이 컸지만 아직 중장비는 남아 있다.","JPN":"ドラコ、山を越える時にダメージを受けたがまだ重機は使えるぞ。","ENG":"Dracasia, we did take some damage while climbing the mountain, but we still have the heavy machinery.","TWN":"德拉克，雖然翻山越嶺導致損失慘重，但怪手還在。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L29_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"이제 모조리 쓸어 버릴 차례야.","JPN":"あとはすべて一掃するだけだ。","ENG":"Now it’s our turn to strike back.","TWN":"現在輪到我們斬草除根囉！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그렇다는데, 코핀 컴퍼니 사장님?","JPN":"って言ってるけど？　コフィンカンパニーの社長？","ENG":"That’s what he says, Mr. CEO of Coffin Company.","TWN":"科芬公司的老闆，有聽到嗎？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"마지막으로 묻는데, 이대로 더 싸우다간 서로 피해만 커질 뿐일세.","JPN":"最後の忠告だが、このまま戦い続けるとお互いの被害が大きくなるだけだ。","ENG":"I’m asking you for the last time. If we fight, it will be a lose-lose situation.","TWN":"我最後再問一次，再這樣打下去也只是兩敗俱傷。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"지금이라도 이번 건에서 손을 뗄 생각은 없나?","JPN":"今からでも間に合う。この件から手を引くつもりはないか？","ENG":"Are you sure you want to go on?","TWN":"你們還是不願意收手嗎？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네들도 애먼 사람들 괴롭히려고 용병 일을 하는 것 같진 않아 보이네만.","JPN":"君たちだって罪のない人々をいじめるために傭兵の仕事をしているようには見えないが。","ENG":"You don’t look like bad guys yourselves.","TWN":"我看你們也不像是會欺負無辜之人的傭兵。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그런 귀여운 얼굴로 진지한 말 하지 말아 줄래? 더 귀여워 보이거든?","JPN":"そんな可愛い顔で真面目なこと言わないでくれる？　もっと可愛くみえちゃーう。","ENG":"Hey, stop. I don’t think I’ll be able to resist your cuteness anymore if you go on.","TWN":"可不可以不要用那麼可愛的臉說正經話？ 因為看起來更可愛！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"아니, 너 진심이었냐?","JPN":"いや、お前本気で言ってんのか？","ENG":"Holy cow, you actually thought he was cute?","TWN":"什麼？你是認真的嗎？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"참 요즘 애들 취향은 알다가도 모르겠네요.","JPN":"今時の若い子の好みって相当変わっていますね。","ENG":"I’ll never understand youngsters these days.","TWN":"最近年輕人的喜好真是難懂。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠. 선입견에 얽매이는 걸 보면 자네도 아직 안목이 부족하군.","JPN":"オホン、先入観に囚われているようなら、君もまだまだ人を見る目がないな。","ENG":"Ahem, I see you still need to work on your people skills.","TWN":"呵呵。你這樣說太有偏見，看來你的眼光還太短淺。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 까놓고 말해서 우리도 의뢰주 시키는 짓거리가 별로 마음에 안 들긴 해.","JPN":"まあ、ぶっちゃけあたしたちだって依頼主からやらされていることは気に食わねえ。","ENG":"Well, to be honest, I don’t really like what my client does.","TWN":"嗯，其實我們也不是很喜歡委託人委託的內容。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하지만 용병 생활의 로망을 채우려면 돈이 있어야지.","JPN":"でも傭兵生活のロマンを実現するためには金が必要なんだよ。","ENG":"But being a mercenary means you need money.","TWN":"只是要想滿足傭兵的夢幻生活，就必須要有錢。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"댁들처럼 그라운드 원에 처박혀서 편하게 사는 중견 태스크포스라면 모를까.","JPN":"お前らみたいにグラウンド・ワンに引っ込んで楽してる中堅タスクフォースカンパニーならともかくさ。","ENG":"Unless I join a TASKFORCE having fun in Ground One, like you.","TWN":"但如果是像你們這種甘願窩在G1，得過且過的特遣勢力可能就不一定啦～"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"방금 그 말, 그냥 듣고 넘어갈 수 없군요.","JPN":"さっきの発言は聞き捨てなりませんね。","ENG":"Oh, having fun is not what I’d call it.","TWN":"剛才那句話恕我無法認同。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"제가 사장님이 만드는 일거리 때문에 얼마나 고생인지 아십니까?","JPN":"私が社長が次々とやらかす厄介事のせいで、どれだけ苦労しているか知っていますか？","ENG":"Do you have any idea how much trouble my Boss brings in?","TWN":"你知道我整天為闖禍的老闆擦屁股有多辛苦嗎？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"조금 숨통이 트였다 싶으면 어디서 어린애들이 배송 오질 않나, 고용한 메이드 때문에 난데없이 체포 작전을 벌이지 않나…….","JPN":"ちょっと息抜きができたと思いきや、どこからか子どもたちが箱で届いたり、雇ったメイドのために突然逮捕作戦を展開するなど……","ENG":"When you think it’s all over, children come to our company packed in a box. Then you go out to apprehend a gang leader for a maid you employed...","TWN":"每當我以為終於可以喘口氣時，要嘛有小孩送過來，要嘛因為雇傭的女僕突然展開逮捕行動……"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"일감은 미어터지는데 순매출은 늘어날 기미가 안 보일 때의 그 아찔한 심정을 아느냔 말입니다.","JPN":"仕事は常に溢れているのに純利益はまったく増える気配がない時の、そのハラハラする立場の気持ちがわかるかと聞いているんです。","ENG":"We’re overwhelmed with work, yet the net profit is still the same. Do you have any idea how frustrating it is?","TWN":"工作量暴增，卻看不到收入有增加的跡象，你明白我的心情有多鬱卒嗎！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"오호……. 의외로 나쁜 남자스러운 면도 있었네.","JPN":"へえ……意外と悪い男の面もあるじゃん。","ENG":"Oh, so you are a badass, huh?","TWN":"喔呵…沒想到你也有壞男人的一面呢！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 흠! 오해일세! 아주 사소한 오해!","JPN":"コホン！　コホン！　誤解だ、ちょっとした誤解だぞ！","ENG":"Ahem! It’s a misunderstanding! A very small misunderstanding!","TWN":"咳咳，誤會！全是誤會！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어쨌든 협상은 이제 결렬이군. 안타까운 결과일세.","JPN":"とにかく交渉決裂だな。残念な結果だ。","ENG":"Anyways, I see the negotiation is over. I’m sorry about this.","TWN":"總之談判破裂，真是遺憾的結果！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"헷. 안타깝긴. 설마 이 상황에 이빨 털면 통할 줄 알았어?","JPN":"へー残念だって？　まさかこの状況でそんな適当な言葉に騙されるとでも思ってんの？","ENG":"Don’t be. Did you really think talking would let you get away with it?","TWN":"哈，遺憾什麼啦！你以爲在這個情況下，耍嘴皮子還行得通嗎？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐 해, 아저씨들? 어서 끝내고 해산해야지!","JPN":"何やってんの、おっさんたち！　さっさと終わらせて解散するぞ！","ENG":"What are you waiting for, old men? Let’s finish this and go home!","TWN":"大叔們在幹嘛？快點結束後原地解散吧！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그, 그렇게는 놔둘 수 없슴다!","JPN":"そ、そうはさせないっす！","ENG":"I-I won’t let you, ma’am!","TWN":"不…不教訓你一下真的不行！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"앙? 이 촌뜨기 꼬마가 끝까지 짜증나게 구네?","JPN":"あ？　田舎者のガキが最後までイライラさせんじゃねぇよ！","ENG":"Huh? This lame kid really IS annoying.","TWN":"嗯？土包子小鬼到現在還在吵？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모네야, 그만둬! 그러다 크게 다치면 어쩌려고!","JPN":"モネ、やめなさい！　怪我でもしたらどうするの！","ENG":"Mone, stop! You’ll hurt yourself!","TWN":"莫妮，住口！萬一受傷怎麼辦！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아부지 없을 때는 모네가 우리 집 가장임다!","JPN":"父ちゃんがいない時はモネが家族を守るっす！","ENG":"When papa is away, Mone is the head of the house!","TWN":"爸爸不在的時候，莫妮就是一家之主！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그러니까 모네는 여기서 한 발짝도 안 물러날 검다!","JPN":"だからここは一歩も通さないっす！","ENG":"So Mone will fight!","TWN":"所以我是絕對不會讓步的！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모, 모네야…….","JPN":"モネ……","ENG":"M-Mone...","TWN":"莫…莫妮……"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"크흑……. 우리 애도 저렇게 대견하면 좋으련만…….","JPN":"ぐすん……うちの子もあんな逞しい子に育ってほしかったな……","ENG":"*Sob* I wish my kids were brave like that.","TWN":"嗚嗚… 真希望我的孩子也這麼懂事……"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"기껏 오랜만에 전화하더니 알파 패드 사달라고 보채기나 하고…….","JPN":"せっかく久しぶりに電話したら最新型のアルファパッドをねだられるだけで……","ENG":"I called them a few days ago and they were screaming for their Alpha Pads...","TWN":"久久才打一次電話，結果只會吵著要買哀Pad……"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"와, 진짜 눈물 난다. 더 보고 있으면 나도 흔들리겠네.","JPN":"わあ、泣いちゃう。こっちの心まで悲しくなりそう。","ENG":"Man, this is so sad. Even I’m getting teary-eyed.","TWN":"嗚嗚，好感人，再這樣下去我都要心軟了！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그러니까 신파극은 이제 끝이야! 라이노 기동시켜!","JPN":"だからもう遊びの時間はおしまいだ！　ライノを起動させろ！","ENG":"So enough of this melodrama! Bring in the Rhino!","TWN":"所以狗血劇就到此為止吧！啟動犀牛！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어머니 말씀이 맞아, 모네 양. 물러서게.","JPN":"お母さんの言うとおりだ、モネ。下がっていなさい。","ENG":"Your mom is right, Mone. Stand back.","TWN":"伯母說得沒錯，莫妮，你退下。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님! 그치만 모네는 우리 마을이 사라지게 두긴 싫슴다!","JPN":"ご主人様！　モネはこの村が破壊されるのを放っておけないっす！","ENG":"But Master! Mone doesn’t want our village to go away!","TWN":"主人！可是我不願意眼睜睜看著村莊被消失！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네와 시그마만으로는 역부족일세.","JPN":"君とシグマだけでは力不足だ。","ENG":"You and Sigma can’t handle it.","TWN":"但光憑你和西格瑪是打不贏他們的！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래서 릴리 양을 통해 부탁해 뒀지. 지원군을 데려오게 말이야.","JPN":"だからリリーに頼んで援軍を呼んである。","ENG":"That’s why I asked Lily to bring reinforcements.","TWN":"所以我有拜託莉莉把援軍帶來。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 마침 저기 오는군.","JPN":"おお、ちょうど着いたみたいだな。","ENG":"Oh, here comes our support.","TWN":"喔，來得正好！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"보스으으! 큰일이야, 큰일!","JPN":"ボスウウゥゥ！　大変だ！","ENG":"Boooosssss! We got trouble! Big trouble!","TWN":"BOSS！不得了啦，不得了啦！"},"stage":{"bg":"SUMMER_BEACH","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"속도 좀 낮춰요! 브레이크 밟을 줄 몰라, 당신?!","JPN":"速度を下げてください！　ブレーキの踏み方も知らないんですか？","ENG":"Slow down! You do know about brakes, right?","TWN":"速度放慢點！你不會踩剎車嗎？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"와아~ 바닷바람이 엄청 시원해요~","JPN":"わあ～潮風がとっても気持ちいいです～","ENG":"Whoa, feel the cool sea breeze!","TWN":"哇～海風特別涼爽～"},"stage":{"bg":"SUMMER_BEACH","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"앗! 뒤에 새카맣게 몰려 오는 저게 지원군인 검까?!","JPN":"あっ！　後ろから大量に押し寄せてくるアレが援軍っすか？","ENG":"Oh? I see a large horde behind them, sir. Are they the reinforcements?","TWN":"嗯？後面那群黑壓壓的就是援軍嗎？！"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으, 응? 저렇게 많이 부른 적은 없는데?","JPN":"え？　あんなに大人数ではないんだが。","ENG":"Huh? But I didn’t ask for that many.","TWN":"嗯？我沒找那麼多人吧？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"주둔지에 있어야 할 음침녀가 왜 저걸 타고 오지? 어떻게 된 거야?","JPN":"アジトにいるはずの陰気な女がなんであれに乗ってんだ？　どういうことだ？","ENG":"Why is that creepy woman here? What’s going on?","TWN":"那個陰沉女不是應該在營地嗎？怎麼會騎著那個東西出現在這裡？怎麼搞的？"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아항. 어째 갑자기 맛이 갔나 했더니, 뒤에서 거래하고 있던 거였군.","JPN":"へえーなんか急に頭がおかしくなったと思ったら、裏で取引をしてたんだ。","ENG":"Oh, I thought she went crazy, but I see she was planning something else.","TWN":"哦哦～還以為她怎麼突然起笑，原來背地裡在搞這些。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"괜찮아. 싸울 줄도 모르는 박사님 한 명 늘어난다고 뭐가 달라지겠어.","JPN":"問題ない。戦い方も知らない博士が一人増えたところで何も変わんねえ。","ENG":"Who cares. Having a doctor who doesn’t even know how to fight won’t really help you.","TWN":"OK的，不過就是多個沒什麼戰力的博士，結果還是一樣的。"},"stage":{"bg":"VILLAGE2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네~!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮～！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네! 모네!","JPN":"モネ！　モネ！　モネ！","ENG":"Mone! Mone! Mone!","TWN":"莫妮！莫妮！莫妮！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그렇다기엔 펭귄들이…… 좀 많이 몰려오는 것 같은데?","JPN":"というにはペンギンの数が……ちょっと多すぎじゃないか？","ENG":"But the penguins... Don’t you think there are too many?","TWN":"我說那個企鵝……是不是有點多？"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"……배, 백 마리인가? 아니, 천 마리?","JPN":"……ひゃ、百匹？　いや、千匹？","ENG":"... A h-hundred? Or... a thousand?","TWN":"…一…一百隻嗎？不，好像有一千隻？"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님, 대체 가서 무슨 헛바람을 불어 넣었던 겁니까?","JPN":"社長、いったい彼女に何を吹き込んだんですか！？","ENG":"Boss, what have you done?","TWN":"老闆，你到底是去跟她胡說八道什麼？"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"별 얘기 안 했어! 요, 용기를 불어 넣어 줬을 뿐이지!","JPN":"別に大した話はしてないぞ！　ゆ、勇気づけてあげただけさ！","ENG":"Nothing! I-I just encouraged her to stand up for herself!","TWN":"我沒說什麼！我…我只是鼓勵她而已！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"시그마 따님! 페, 펭귄들이 엄청 몰려오고 있슴다!","JPN":"シグマお嬢様！　と、とんでもない数のペンギンたちが押し寄せてきます！","ENG":"Sigma Lady! P-penguins, a lot of penguins are coming this way!","TWN":"西格瑪千金！好…好多企鵝衝過來啦！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응! 오늘도 다 같이 신나게 놀 수 있겠다!","JPN":"やった！　今日もみんなで楽しく遊べるね！","ENG":"Yes! We’ll have such a fun today!","TWN":"嗯！今天又能一起開心玩囉～！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그보다 마을이 펭귄으로 꽉 차 버릴 검다!","JPN":"それより村がペンギンで溢れちゃうっす！","ENG":"The whole village will be flooded with penguins, ma’am!","TWN":"可是村裡會擠滿企鵝欸！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"무기를 들어라! 전원 전투 준비!!","JPN":"武器を持て！　全員戦闘準備！！","ENG":"To arms! Prepare for battle!!","TWN":"拿起武器！準備作戰！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L26_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"작전 목표는…… 살아남기다!","JPN":"作戦目標は……生き残ること！","ENG":"Our goal is to... survive!","TWN":"作戰目標是… 活命！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}}]`);export{e as default};